def path(rel: str) -> Path:
    return ROOT / rel


def read(rel: str) -> str:
    return path(rel).read_text(encoding="utf-8")


def write(rel: str, content: str) -> None:
    target = path(rel)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content.rstrip() + "\n", encoding="utf-8")


def append_once(rel: str, section: str) -> None:
    if not section:
        return
    text = read(rel)
    if MARKER in text:
        return
    write(rel, text.rstrip() + "\n\n" + section.strip() + "\n")


def replace_once(rel: str, old: str, new: str) -> None:
    text = read(rel)
    if new in text:
        return
    if old not in text:
        raise SystemExit(f"{rel}: replacement anchor not found: {old!r}")
    write(rel, text.replace(old, new, 1))


def insert_before(rel: str, anchor: str, section: str) -> None:
    text = read(rel)
    if MARKER in text:
        return
    if anchor not in text:
        raise SystemExit(f"{rel}: insertion anchor not found: {anchor!r}")
    write(rel, text.replace(anchor, section.rstrip() + "\n\n" + anchor, 1))


def insert_after_text(rel: str, anchor: str, addition: str, unique_text: str) -> None:
    text = read(rel)
    if unique_text in text:
        return
    if anchor not in text:
        raise SystemExit(f"{rel}: insertion anchor not found")
    write(rel, text.replace(anchor, anchor + addition, 1))


