def main() -> None:
    for rel, content in FILES.items():
        write(rel, content)

    update_indices_and_readme()

    for rel, section in APPEND_SECTIONS.items():
        if rel in {
            "docs/project-buildout/README.md",
        }:
            continue
        append_once(rel, section)

    update_repository_map()
    update_json_controls()
    update_controls_and_workflow()
    update_validator()

